(function() {
  'use strict';

  if (window.__ghDirDownloadActive) return;
  window.__ghDirDownloadActive = true;

  var BUTTON_ID = 'ba-gh-dir-download';

  function parseRepoPath() {
    var match = location.pathname.match(/^\/([^/]+)\/([^/]+)\/tree\/([^/]+)\/(.+)/);
    if (!match) return null;
    return {
      owner: match[1],
      repo: match[2],
      branch: match[3],
      path: decodeURIComponent(match[4])
    };
  }

  function pathKey(info) {
    return info.owner + '/' + info.repo + '/' + info.branch + '/' + info.path;
  }

  /* ── Minimal store-only ZIP builder (no compression) ── */
  function crc32(buf) {
    var table = new Uint32Array(256);
    for (var i = 0; i < 256; i++) {
      var c = i;
      for (var j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c;
    }
    var crc = 0xFFFFFFFF;
    for (var k = 0; k < buf.length; k++) crc = table[(crc ^ buf[k]) & 0xFF] ^ (crc >>> 8);
    return (crc ^ 0xFFFFFFFF) >>> 0;
  }

  function buildZip(files) {
    var localHeaders = [];
    var centralHeaders = [];
    var offset = 0;
    var encoder = new TextEncoder();
    for (var i = 0; i < files.length; i++) {
      var nameBytes = encoder.encode(files[i].name);
      var data = new Uint8Array(files[i].data);
      var checksum = crc32(data);
      var localHeader = new Uint8Array(30 + nameBytes.length);
      var lv = new DataView(localHeader.buffer);
      lv.setUint32(0, 0x04034b50, true);
      lv.setUint16(4, 20, true);
      lv.setUint16(8, 0, true);
      lv.setUint32(14, checksum, true);
      lv.setUint32(18, data.length, true);
      lv.setUint32(22, data.length, true);
      lv.setUint16(26, nameBytes.length, true);
      localHeader.set(nameBytes, 30);
      localHeaders.push(localHeader);
      localHeaders.push(data);
      var centralHeader = new Uint8Array(46 + nameBytes.length);
      var cv = new DataView(centralHeader.buffer);
      cv.setUint32(0, 0x02014b50, true);
      cv.setUint16(4, 20, true);
      cv.setUint16(6, 20, true);
      cv.setUint16(12, 0, true);
      cv.setUint32(16, checksum, true);
      cv.setUint32(20, data.length, true);
      cv.setUint32(24, data.length, true);
      cv.setUint16(28, nameBytes.length, true);
      cv.setUint32(42, offset, true);
      centralHeader.set(nameBytes, 46);
      centralHeaders.push(centralHeader);
      offset += localHeader.length + data.length;
    }
    var centralSize = centralHeaders.reduce(function(s, h) { return s + h.length; }, 0);
    var endRecord = new Uint8Array(22);
    var ev = new DataView(endRecord.buffer);
    ev.setUint32(0, 0x06054b50, true);
    ev.setUint16(8, files.length, true);
    ev.setUint16(10, files.length, true);
    ev.setUint32(12, centralSize, true);
    ev.setUint32(16, offset, true);
    var parts = localHeaders.concat(centralHeaders, [endRecord]);
    var totalSize = parts.reduce(function(s, p) { return s + p.length; }, 0);
    var result = new Uint8Array(totalSize);
    var pos = 0;
    for (var p = 0; p < parts.length; p++) {
      result.set(parts[p], pos);
      pos += parts[p].length;
    }
    return new Blob([result], { type: 'application/zip' });
  }

  function encodePath(path) {
    return path.split('/').map(encodeURIComponent).join('/');
  }

  /* ── Listing: Trees API (one request), Contents-API fallback when truncated ── */
  async function listFiles(info) {
    var apiUrl = 'https://api.github.com/repos/' + info.owner + '/' + info.repo +
      '/git/trees/' + encodeURIComponent(info.branch) + '?recursive=1';
    var resp = await fetch(apiUrl, { headers: { 'Accept': 'application/vnd.github+json' } });
    if (!resp.ok) {
      throw new Error('GitHub API ' + resp.status + (resp.status === 403 ? ' (rate limit — 60/hr unauthenticated)' : ''));
    }
    var data = await resp.json();
    if (data.truncated) return await listViaContents(info, info.path);
    var prefix = info.path + '/';
    return data.tree
      .filter(function(item) { return item.type === 'blob' && item.path.indexOf(prefix) === 0; })
      .map(function(item) { return item.path; });
  }

  async function listViaContents(info, dir) {
    var paths = [];
    var url = 'https://api.github.com/repos/' + info.owner + '/' + info.repo +
      '/contents/' + encodePath(dir) + '?ref=' + encodeURIComponent(info.branch);
    var resp = await fetch(url, { headers: { 'Accept': 'application/vnd.github+json' } });
    if (!resp.ok) throw new Error('GitHub API ' + resp.status);
    var items = await resp.json();
    for (var i = 0; i < items.length; i++) {
      if (items[i].type === 'dir') {
        paths = paths.concat(await listViaContents(info, items[i].path));
      } else if (items[i].type === 'file') {
        paths.push(items[i].path);
      }
    }
    return paths;
  }

  /* ── Content: raw.githubusercontent.com — NOT counted against the API limit ── */
  function rawUrl(info, path) {
    return 'https://raw.githubusercontent.com/' + info.owner + '/' + info.repo +
      '/' + encodeURIComponent(info.branch) + '/' + encodePath(path);
  }

  async function fetchRaw(url) {
    var resp = await fetch(url);
    if (!resp.ok) throw new Error('fetch ' + resp.status);
    return await resp.arrayBuffer();
  }

  async function downloadDirectory(info, button) {
    try {
      button.textContent = 'Listing files...';
      button.disabled = true;

      var paths = await listFiles(info);
      if (paths.length === 0) {
        button.textContent = 'No files found';
        setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 2000);
        return;
      }

      var dirName = info.path.split('/').pop() || info.repo;
      var files = [];
      var done = 0;
      var queue = paths.slice();

      async function worker() {
        while (queue.length) {
          var path = queue.shift();
          var rel = path.substring(info.path.length + 1);
          try {
            var buf = await fetchRaw(rawUrl(info, path));
            files.push({ name: rel, data: buf });
          } catch (e) {
            console.warn('[GH Dir Download] skipped', path, e);
          }
          done++;
          button.textContent = 'Downloading ' + done + '/' + paths.length + '...';
        }
      }

      var workers = [];
      for (var w = 0; w < 8; w++) workers.push(worker());
      await Promise.all(workers);

      if (files.length === 0) throw new Error('no files could be fetched');

      button.textContent = 'Creating ZIP...';
      var zipBlob = buildZip(files);
      var a = document.createElement('a');
      a.href = URL.createObjectURL(zipBlob);
      a.download = dirName + '.zip';
      a.click();
      URL.revokeObjectURL(a.href);

      button.textContent = 'Downloaded!';
      setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 2000);
    } catch (err) {
      console.error('[GH Dir Download]', err);
      button.textContent = 'Error: ' + (err && err.message ? err.message : 'failed');
      setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 3000);
    }
  }

  function makeButton(info) {
    var btn = document.createElement('button');
    btn.id = BUTTON_ID;
    btn.type = 'button';
    btn.textContent = 'Download Directory';
    btn.setAttribute('data-ba-path', pathKey(info));
    btn.style.cssText = 'margin:0 8px;padding:5px 16px;font-size:14px;font-weight:500;line-height:20px;cursor:pointer;border:1px solid var(--borderColor-default,rgba(27,31,36,0.15));border-radius:6px;color:#fff;background-color:#1f883d;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Helvetica,Arial,sans-serif;';
    btn.addEventListener('mouseenter', function() { btn.style.backgroundColor = '#1a7f37'; });
    btn.addEventListener('mouseleave', function() { btn.style.backgroundColor = '#1f883d'; });
    btn.addEventListener('click', function() { downloadDirectory(info, btn); });
    return btn;
  }

  function injectButton() {
    var info = parseRepoPath();
    var existing = document.getElementById(BUTTON_ID);
    if (!info) { if (existing) existing.remove(); return; }
    if (existing) {
      if (existing.getAttribute('data-ba-path') === pathKey(info)) return; // already current
      existing.remove(); // stale (SPA navigated to another directory)
    }

    var btn = makeButton(info);

    // Preferred: just before the "..." overflow-menu button in the file-list header row.
    var overflow = document.querySelector('[data-testid="tree-overflow-menu-anchor"]');
    if (overflow && overflow.parentElement) {
      overflow.parentElement.insertBefore(btn, overflow);
      return;
    }
    // Fallback: the "Folders and files" listing region.
    var region = document.querySelector('#folders-and-files') ||
      document.querySelector('div[aria-labelledby="folders-and-files"]');
    if (region && region.parentElement) {
      region.parentElement.insertBefore(btn, region);
      return;
    }
    // Last resort: the first file-listing row.
    var col = document.querySelector('.react-directory-filename-column');
    var row = col && col.closest('.react-directory-row');
    if (row && row.parentElement) {
      row.parentElement.insertBefore(btn, row);
    }
  }

  var scheduled = false;
  function schedule() {
    if (scheduled) return;
    scheduled = true;
    requestAnimationFrame(function() {
      scheduled = false;
      injectButton();
    });
  }

  schedule();

  /* GitHub is a Turbo/SPA: re-inject on hard load, tab nav, and folder-to-folder nav. */
  window.addEventListener('turbo:load', schedule);
  document.addEventListener('soft-nav:end', schedule);

  var observer = new MutationObserver(schedule);
  observer.observe(document.body, { childList: true, subtree: true });

  console.log('[GitHub Directory Download] Active — look for the download button on directory pages.');
})();
